import json

# Access the stored business data
business_data = locals()['var_functions.query_db:16']

# Initialize result dictionary
result_data = {
    'total_businesses': 0,
    'first_business_sample': None
}

# Process data if available
if business_data and isinstance(business_data, list):
    result_data['total_businesses'] = len(business_data)
    if len(business_data) > 0:
        first_business = business_data[0]
        result_data['first_business_sample'] = {
            'keys': list(first_business.keys()),
            'description_preview': str(first_business.get('description', ''))[:150]
        }

print('__RESULT__:')
print(json.dumps(result_data))

